def solve():
    import sys
    from collections import deque

    data = sys.stdin.read().split()
    idx = 0
    r = int(data[idx]); idx += 1
    c = int(data[idx]); idx += 1
    grid = []
    for _ in range(r):
        row = list(map(int, data[idx:idx + c]))
        idx += c
        grid.append(row)

    q = deque()
    zero_count = 0
    for i in range(r):
        for j in range(c):
            if grid[i][j] == 1:
                q.append((i, j, 0))  # 처음부터 익은 토마토를 시작점으로 등록
            elif grid[i][j] == 0:
                zero_count += 1

    max_day = 0
    ripened_zero = 0
    while q:
        y, x, d = q.popleft()
        max_day = max(max_day, d)
        for dy, dx in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            ny, nx = y + dy, x + dx
            if 0 <= ny < r and 0 <= nx < c and grid[ny][nx] == 0:
                grid[ny][nx] = 1
                ripened_zero += 1
                q.append((ny, nx, d + 1))

    if ripened_zero < zero_count:
        print(-1)
    else:
        print(max_day)

solve()
